// Simula processamento de IA (delay de 2-4 segundos)
const delay = 2000 + Math.random() * 2000;
await new Promise(resolve => setTimeout(resolve, delay));

const input = $input.all()[0].json;

return [{
  json: {
    status: 'processado',
    request_id: input.body?.request_id || 'unknown',
    canal: input.body?.canal || 'desconhecido',
    prioridade: input.body?.prioridade || 'media',
    mensagem_original: input.body?.mensagem || '',
    resposta_ia: `Resposta simulada de IA para requisição #${input.body?.request_id}`,
    worker: 'worker-' + Math.random().toString(36).substring(2, 8),
    tempo_processamento_ms: Math.round(delay),
    timestamp: new Date().toISOString()
  }
}];
